@Repository
public interface UserRepository
    extends JpaRepository<User, UUID>, JpaSpecificationExecutor<User> {

    Optional<User> findByEmail(String email);
    boolean existsByEmailAndOrganizationId(String email, UUID orgId);

    @Query("SELECT u FROM User u WHERE u.organization.id = :orgId AND u.active = true")
    Page<User> findActiveByOrganization(@Param("orgId") UUID orgId, Pageable pageable);
}

public class UserSpecification {
    public static Specification<User> inOrganization(UUID orgId) {
        return (root, q, cb) -> cb.equal(root.get("organization").get("id"), orgId);
    }
    public static Specification<User> isActive(boolean active) {
        return (root, q, cb) -> cb.equal(root.get("active"), active);
    }
}

@Service
@RequiredArgsConstructor
@Slf4j
@Transactional(readOnly = true)
public class UserServiceImpl implements UserService {

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final UserMapper userMapper;

    @Override
    @Transactional   // write override
    public UserResponse create(CreateUserRequest request, UUID orgId) {
        if (userRepository.existsByEmailAndOrganizationId(request.email(), orgId)) {
            throw new BusinessException("Email already exists");
        }
        var user = User.builder()
            .name(request.name())
            .email(request.email().toLowerCase())
            .password(passwordEncoder.encode(request.password()))
            .build();
        return userMapper.toResponse(userRepository.save(user));
    }

    @Override
    public UserResponse getById(UUID id) {
        return userRepository.findById(id)
            .map(userMapper::toResponse)
            .orElseThrow(() -> new ResourceNotFoundException("User", id));
    }

    @Override
    public Page<UserResponse> search(UUID orgId, String search, Pageable pageable) {
        Specification<User> spec = Specification
            .where(UserSpecification.inOrganization(orgId))
            .and(UserSpecification.isActive(true));
        if (search != null && !search.isBlank())
            spec = spec.and(UserSpecification.searchByNameOrEmail(search));
        return userRepository.findAll(spec, pageable).map(userMapper::toResponse);
    }
}
